// ─── AetheronBridge ──────────────────────────────────────────────────────────

export interface BridgeRequest {
  token: string;
  amount: BigNumberish;
  destinationChain: BigNumberish;
  recipient: string;
  maxSlippage: BigNumberish;
  deadline: BigNumberish;
}

export interface AetheronBridge extends BaseContract {
  connect(signer: Signer): this;

  // roles
  RELAYER_ROLE(): Promise<string>;
  SENTINEL_ROLE(): Promise<string>;
  DEFAULT_ADMIN_ROLE(): Promise<string>;

  // state
  treasury(): Promise<string>;
  sentinelInterceptor(): Promise<string>;
  bridgeFeePercent(): Promise<bigint>;
  transferNonce(): Promise<bigint>;
  totalValueLocked(): Promise<bigint>;
  supportedChains(chainId: BigNumberish): Promise<boolean>;
  supportedTokens(token: string): Promise<boolean>;
  completedTransfers(transferId: BytesLike): Promise<boolean>;
  paused(): Promise<boolean>;

  // core bridge
  bridge(
    request: BridgeRequest,
    overrides?: { value?: BigNumberish },
  ): Promise<ContractTransactionResponse>;
  completeBridge(
    transferId: BytesLike,
    token: string,
    amount: BigNumberish,
    recipient: string,
  ): Promise<ContractTransactionResponse>;

  // admin
  emergencyPause(): Promise<ContractTransactionResponse>;
  resume(): Promise<ContractTransactionResponse>;
  setSentinel(newSentinel: string): Promise<ContractTransactionResponse>;
  setSupportedChain(
    chainId: BigNumberish,
    supported: boolean,
  ): Promise<ContractTransactionResponse>;
  setBridgeFee(newFee: BigNumberish): Promise<ContractTransactionResponse>;
  setTreasury(newTreasury: string): Promise<ContractTransactionResponse>;
  rescueTokens(
    token: string,
    to: string,
  ): Promise<ContractTransactionResponse>;
  addSupportedToken(token: string): Promise<ContractTransactionResponse>;
  grantRole(
    role: BytesLike,
    account: string,
  ): Promise<ContractTransactionResponse>;
  revokeRole(
    role: BytesLike,
    account: string,
  ): Promise<ContractTransactionResponse>;
  hasRole(role: BytesLike, account: string): Promise<boolean>;

  // view
  getBridgeStats(): Promise<[boolean, bigint, bigint]>;
  isTransferCompleted(transferId: BytesLike): Promise<boolean>;
  calculateTVL(): Promise<bigint>;
}

export interface AetheronBridge__factory {
  deploy(
    sentinelInterceptor: string,
    treasury: string,
    initialAdmin: string,
    overrides?: object,
  ): Promise<AetheronBridge>;
  connect(signer: Signer): AetheronBridge__factory;
}

// ─── SentinelInterceptor ─────────────────────────────────────────────────────

export interface SentinelInterceptor extends BaseContract {
  connect(signer: Signer): this;

  // roles
  SENTINEL_ROLE(): Promise<string>;
  ORACLE_ROLE(): Promise<string>;
  DEFAULT_ADMIN_ROLE(): Promise<string>;

  // constants
  TVL_SPIKE_THRESHOLD(): Promise<bigint>;
  MAX_PAUSE_DURATION(): Promise<bigint>;
  WITHDRAWAL_WINDOW(): Promise<bigint>;

  // state
  bridgeAddress(): Promise<string>;
  totalValueLocked(): Promise<bigint>;
  lastPauseTimestamp(): Promise<bigint>;
  autonomousMode(): Promise<boolean>;
  cumulativeWithdrawals(): Promise<bigint>;
  paused(): Promise<boolean>;

  // core
  reportAnomaly(
    tvlPercentage: BigNumberish,
    currentTVL: BigNumberish,
  ): Promise<ContractTransactionResponse>;
  emergencyPause(reason: string): Promise<ContractTransactionResponse>;
  resumeBridge(newTVL: BigNumberish): Promise<ContractTransactionResponse>;
  updateTVL(newTVL: BigNumberish): Promise<ContractTransactionResponse>;
  setAutonomousMode(enabled: boolean): Promise<ContractTransactionResponse>;
  updateThreshold(
    newThreshold: BigNumberish,
  ): Promise<ContractTransactionResponse>;

  // access control
  grantRole(
    role: BytesLike,
    account: string,
  ): Promise<ContractTransactionResponse>;
  revokeRole(
    role: BytesLike,
    account: string,
  ): Promise<ContractTransactionResponse>;
  hasRole(role: BytesLike, account: string): Promise<boolean>;

  // view
  getSecurityStatus(): Promise<[boolean, bigint, boolean]>;
  getResponseMetrics(): Promise<[bigint, bigint, bigint]>;
}

export interface SentinelInterceptor__factory {
  deploy(
    bridgeAddress: string,
    initialAdmin: string,
    overrides?: object,
  ): Promise<SentinelInterceptor>;
  connect(signer: Signer): SentinelInterceptor__factory;
}

